import{_ as r,o as a,c as e,a2 as o}from"./chunks/framework.BFVZdVmd.js";const g=JSON.parse('{"title":"Spring 核心","description":"","frontmatter":{},"headers":[],"relativePath":"spring-core/index.md","filePath":"spring-core/index.md","lastUpdated":null}'),i={name:"spring-core/index.md"};function n(d,t,l,p,s,h){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="spring-核心" tabindex="-1">Spring 核心 <a class="header-anchor" href="#spring-核心" aria-label="Permalink to &quot;Spring 核心&quot;">​</a></h1><blockquote><p>本栏目为知识库新增内容，不属于《Spring 技术套件》原文档。</p></blockquote><p><a href="/my-docs/framework/">核心框架</a>栏目讲的是「用 Spring Boot 搭微服务」，本栏目讲的是<strong>底层原理</strong>：Spring 到底做了什么、为什么这么设计。理解这些，才能看懂自动配置、排查 Bean 注入和事务失效问题、写出合理的 AOP 切面。</p><h2 id="为什么要懂原理" tabindex="-1">为什么要懂原理 <a class="header-anchor" href="#为什么要懂原理" aria-label="Permalink to &quot;为什么要懂原理&quot;">​</a></h2><p>每个微服务本质都是一个 Spring 应用。日常开发中大量「玄学问题」其实都源于对核心机制的不了解：</p><ul><li><code>@Autowired</code> 注入为 null</li><li><code>@Transactional</code> 不生效、回滚不了</li><li>循环依赖报错</li><li>AOP 切面没拦截到方法</li><li>自动配置没生效</li></ul><p>这些都需要理解 IoC 容器、AOP 代理、事务的工作机制。</p><h2 id="本栏目内容" tabindex="-1">本栏目内容 <a class="header-anchor" href="#本栏目内容" aria-label="Permalink to &quot;本栏目内容&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>说明</th></tr></thead><tbody><tr><td><a href="./ioc">IoC 与依赖注入</a></td><td>容器、Bean 生命周期、注入方式、循环依赖</td></tr><tr><td><a href="./aop">AOP 面向切面</a></td><td>动态代理、切面、应用场景</td></tr><tr><td><a href="./transaction">事务原理</a></td><td>声明式事务、传播行为、失效场景</td></tr></tbody></table><h2 id="spring-全家桶定位" tabindex="-1">Spring 全家桶定位 <a class="header-anchor" href="#spring-全家桶定位" aria-label="Permalink to &quot;Spring 全家桶定位&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>作用</th></tr></thead><tbody><tr><td>Spring Framework</td><td>核心：IoC、AOP、事务、MVC</td></tr><tr><td>Spring Boot</td><td>自动配置、起步依赖、内嵌容器，简化 Spring 应用搭建</td></tr><tr><td>Spring Cloud</td><td>在 Spring Boot 之上提供微服务治理能力</td></tr></tbody></table><p>Spring Boot 不是替代 Spring，而是<strong>让 Spring 更易用</strong>。理解 Spring Framework 的核心，才能理解 Boot 的自动配置在帮你做什么。</p>',12)])])}const S=r(i,[["render",n]]);export{g as __pageData,S as default};
